module clken_buf (clk, rclk, enb_l, tmb_l);
output clk;
input  rclk, enb_l, tmb_l;
reg    clken;
  always @ (rclk or enb_l or tmb_l)
    if (!rclk)  
      clken = !enb_l | !tmb_l;
  assign clk = clken & rclk;
  always @(*) begin
    if (1'b0) begin
      if (enb_l) begin
        clken <= 1'b0;
      end else if (tmb_l) begin
        clken <= 1'b0;
      end
    end
  end

endmodule

